const listTenantTranscriptions = `-- name: ListTenantTranscriptions :many
select id, tenant_id, recording_id, room_id, session_id, status, provider, model, languages, metadata, completed_at, updated_at, created_at, artifact_key, artifact_sha256, artifact_size, artifact_content_type, source_manifest_key, source_manifest_sha256, source_manifest_size, source_manifest_content_type, generation, deleted_at from transcriptions
where tenant_id = $1
  and ($2::uuid is null or recording_id = $2::uuid)
  and (not $3::boolean or (created_at, id) < ($4::timestamptz, $5::uuid))
order by created_at desc, id desc
limit $6::integer
`

type ListTenantTranscriptionsParams struct {
	TenantID        pgtype.UUID        `json:"tenant_id"`
	RecordingID     pgtype.UUID        `json:"recording_id"`
	CursorSet       bool               `json:"cursor_set"`
	CursorCreatedAt pgtype.Timestamptz `json:"cursor_created_at"`
	CursorID        pgtype.UUID        `json:"cursor_id"`
	PageSize        int32              `json:"page_size"`
}

func (q *Queries) ListTenantTranscriptions(ctx context.Context, arg ListTenantTranscriptionsParams) ([]Transcription, error) {
	rows, err := q.db.Query(ctx, listTenantTranscriptions,
		arg.TenantID,
		arg.RecordingID,
		arg.CursorSet,
		arg.CursorCreatedAt,
		arg.CursorID,
		arg.PageSize,
	)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	var items []Transcription
	for rows.Next() {
		var i Transcription
		if err := rows.Scan(
			&i.ID,
			&i.TenantID,
			&i.RecordingID,
			&i.RoomID,
			&i.SessionID,
			&i.Status,
			&i.Provider,
			&i.Model,
			&i.Languages,
			&i.Metadata,
			&i.CompletedAt,
			&i.UpdatedAt,
			&i.CreatedAt,
			&i.ArtifactKey,
			&i.ArtifactSha256,
			&i.ArtifactSize,
			&i.ArtifactContentType,
			&i.SourceManifestKey,
			&i.SourceManifestSha256,
			&i.SourceManifestSize,
			&i.SourceManifestContentType,
			&i.Generation,
			&i.DeletedAt,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

